mapper.update:
UPDATE `screen_rental_order` SET
status = #{data.status}, remark = #{data.remark}, update_time = NOW(),
WHERE id = #{data.id}

mapper.select:
SELECT COUNT(1)                     AS orderCount,
       COALESCE(SUM(o.total_amount), 0) AS totalAmount
FROM `screen_rental_order` o
         LEFT JOIN `shop` s ON s.id = o.shop_id
         LEFT JOIN `equipment` e ON e.id = o.equipment_id
WHERE s.merchant_id = #{adminId}
  AND o.order_time  >=  #{startTime}
  AND o.order_time  <=  #{endTime}

    AND o.status = #{param.status}


    AND o.business_circle_name LIKE CONCAT('%', #{param.businessCircleName}, '%')


    AND e.serial_number LIKE CONCAT('%', #{param.serialNumber}, '%')

SELECT o.id AS orderId, o.order_no AS orderNo, o.order_time AS orderTime, o.status AS status, o.equipment_id AS equipmentId, e.serial_number AS serialNumber, o.total_amount AS totalAmount, o.business_circle_id AS businessCircleId, o.business_circle_name AS businessCircleName, o.shop_id AS shopId, o.shop_name AS shopName, d.rental_months AS rentalMonths, o.remark AS remark FROM `screen_rental_order` o LEFT JOIN `shop` s ON s.id = o.shop_id LEFT JOIN `equipment` e ON e.id = o.equipment_id LEFT JOIN (SELECT order_id, GROUP_CONCAT(CONCAT(rental_year, '.', LPAD(rental_month, 2, '0')) ORDER BY rental_year, rental_month SEPARATOR '、') AS rental_months FROM `screen_rental_detail` GROUP BY order_id) d ON d.order_id = o.id WHERE s.merchant_id = #{adminId} AND o.order_time >= #{startTime} AND o.order_time <= #{endTime}
AND o.status = #{param.status}
AND o.business_circle_name LIKE CONCAT('%', #{param.businessCircleName}, '%')
AND e.serial_number LIKE CONCAT('%', #{param.serialNumber}, '%')
ORDER BY o.order_time DESC, o.id DESC

SELECT COUNT(1) AS orderCount, COALESCE(SUM(o.total_amount), 0) AS totalAmount FROM `screen_rental_order` o LEFT JOIN `equipment` e ON e.id = o.equipment_id LEFT JOIN `shop` s ON s.id = o.shop_id LEFT JOIN `merchant` m ON m.id = s.merchant_id WHERE 1 = 1
AND o.order_time >= #{param.startTime}
AND o.order_time <= #{param.endTime}
AND e.serial_number LIKE CONCAT('%', #{param.serialNumber}, '%')
AND o.business_circle_name LIKE CONCAT('%', #{param.businessCircleName}, '%')
AND COALESCE(m.merchant_name, o.shop_name) LIKE CONCAT('%', #{param.merchantName}, '%')
AND (o.nick_name LIKE CONCAT('%', #{param.orderUserKeyword}, '%') OR o.phone LIKE CONCAT('%', #{param.orderUserKeyword}, '%'))
AND o.order_no LIKE CONCAT('%', #{param.orderNo}, '%')
AND o.status = #{param.status}

SELECT o.id AS orderId, o.order_time AS orderTime, e.serial_number AS serialNumber, o.business_circle_name AS businessCircleName, COALESCE(m.merchant_name, o.shop_name) AS merchantName, o.total_amount AS totalAmount, d.rental_months AS rentalMonths, CASE WHEN o.nick_name IS NULL OR o.nick_name = '' THEN COALESCE(o.phone, '') WHEN o.phone IS NULL OR o.phone = '' THEN o.nick_name ELSE CONCAT(o.nick_name, ' ', o.phone) END AS orderUserText, o.order_no AS orderNo, o.status AS status, o.remark AS remark FROM `screen_rental_order` o LEFT JOIN `equipment` e ON e.id = o.equipment_id LEFT JOIN `shop` s ON s.id = o.shop_id LEFT JOIN `merchant` m ON m.id = s.merchant_id LEFT JOIN (SELECT order_id, GROUP_CONCAT(CONCAT(rental_year, '.', LPAD(rental_month, 2, '0')) ORDER BY rental_year, rental_month SEPARATOR '、') AS rental_months FROM `screen_rental_detail` GROUP BY order_id) d ON d.order_id = o.id WHERE 1 = 1
AND o.order_time >= #{param.startTime}
AND o.order_time <= #{param.endTime}
AND e.serial_number LIKE CONCAT('%', #{param.serialNumber}, '%')
AND o.business_circle_name LIKE CONCAT('%', #{param.businessCircleName}, '%')
AND COALESCE(m.merchant_name, o.shop_name) LIKE CONCAT('%', #{param.merchantName}, '%')
AND (o.nick_name LIKE CONCAT('%', #{param.orderUserKeyword}, '%') OR o.phone LIKE CONCAT('%', #{param.orderUserKeyword}, '%'))
AND o.order_no LIKE CONCAT('%', #{param.orderNo}, '%')
AND o.status = #{param.status}
ORDER BY o.order_time DESC, o.id DESC
